const newMailId = $("Oldest_Unhandle_Mail").first().json.id;
const newMail = $("Oldest_Unhandle_Mail").first(); //$input.all().find(x => x.json.id === newMailId);
const mailConversation = $input.first().json.value.filter(x => x.id != newMailId);
if (!newMail) {
 return {
 isSuccess: false
 }
}

const hasPrevMail = mailConversation.length > 0;
let prevMail = []
for (let i = 0; i < mailConversation.length; i ++){
 const object = {
 subject: mailConversation[i].subject,
 from: mailConversation[i].from.emailAddress.address,
 to: mailConversation[i].toRecipients.map(x=> x.emailAddress.address).join(';'),
 body: mailConversation[i].body.content,
 receiveTime: mailConversation[i].receivedDateTime
 }
 prevMail.push(object)
}


return {
 isSuccess: true,
 newMail: {
 id: newMail.json.id,
 subject: newMail.json.subject,
 from: newMail.json.from.emailAddress.address,
 to: newMail.json.toRecipients.map(x=> x.emailAddress.address).join(';'),
 body: newMail.json.body.content.split("________________________________")[0],
 receiveTime: newMail.json.receivedDateTime
 },
 hasPrevMail: hasPrevMail,
 prevMail: prevMail
}

var mail = $input.all().find(function(x) { return x.json.newMail; });
if(!mail) {
 return {
 isFail: true
 };
}
var incoming_mail = mail.json.newMail;
var previous_mails = mail.json.prevMail;

var content = '\n**Here is incoming email:-------------------\nSubject: ' + incoming_mail.subject + ' \nFrom: ' + incoming_mail.from + '\nTo: ' + incoming_mail.to + '\nBody: \n' + incoming_mail.body + '\n-------------------\n';

if (previous_mails && previous_mails.length) {
 content += '**Here is previous email conversation:\n';
 var sortedList = previous_mails.sort(function(a, b) {
 return new Date(b.receiveTime).getTime() - new Date(a.receiveTime).getTime();
 }); 
 for (var i = 0; i < sortedList.length; i++) {
 content += '--------Mail ' + (i+1) + ':-----------\nSubject: ' + previous_mails[i].subject + ' \nFrom: ' + previous_mails[i].from + '\nTo: ' + previous_mails[i].to + '\nBody: \n' + previous_mails[i].body + '\n-------------------\n';
 }
}

return {
 content: content,
 isFail: false
};

